const accountTag = 'replace-with-cloudflare-account-id';
if (accountTag === 'replace-with-cloudflare-account-id') {
  throw new Error('Set the Cloudflare account ID in this node before activating the workflow.');
}

const end = new Date();
const start = new Date(end.getTime() - 7 * 24 * 60 * 60 * 1000);
const startIso = start.toISOString();
const endIso = end.toISOString();

const query = `query WeeklyRum($accountTag: string!, $start: Time!, $end: Time!) {
  viewer {
    accounts(filter: { accountTag: $accountTag }) {
      kheTotal: rumPageloadEventsAdaptiveGroups(limit: 1, filter: { datetime_geq: $start, datetime_leq: $end, requestHost: "khe.ee", bot: 0 }) {
        count
        sum { visits }
      }
      kheTopPages: rumPageloadEventsAdaptiveGroups(limit: 8, orderBy: [count_DESC], filter: { datetime_geq: $start, datetime_leq: $end, requestHost: "khe.ee", bot: 0 }) {
        count
        sum { visits }
        dimensions { requestPath }
      }
      gamesTotal: rumPageloadEventsAdaptiveGroups(limit: 1, filter: { datetime_geq: $start, datetime_leq: $end, requestHost: "games.khe.ee", bot: 0 }) {
        count
        sum { visits }
      }
      gamesTopPages: rumPageloadEventsAdaptiveGroups(limit: 8, orderBy: [count_DESC], filter: { datetime_geq: $start, datetime_leq: $end, requestHost: "games.khe.ee", bot: 0 }) {
        count
        sum { visits }
        dimensions { requestPath }
      }
    }
  }
}`;

return [{
  json: {
    generatedAt: endIso,
    period: {
      start: startIso,
      end: endIso,
      days: 7
    },
    request: {
      query,
      variables: {
        accountTag,
        start: startIso,
        end: endIso
      }
    }
  }
}];

const source = $input.first().json;
if (source.errors?.length) {
  throw new Error(`Cloudflare GraphQL error: ${JSON.stringify(source.errors)}`);
}

const account = source.data?.viewer?.accounts?.[0] ?? {};
const meta = $('Build Cloudflare Query').first().json;

function totals(rows) {
  const row = Array.isArray(rows) ? rows[0] : undefined;
  return {
    pageViews: Number(row?.count ?? 0),
    visits: Number(row?.sum?.visits ?? 0)
  };
}

function topPages(rows) {
  return (Array.isArray(rows) ? rows : [])
    .map((row) => ({
      path: row?.dimensions?.requestPath || '/',
      pageViews: Number(row?.count ?? 0),
      visits: Number(row?.sum?.visits ?? 0)
    }))
    .filter((row) => row.pageViews > 0);
}

return [{
  json: {
    generatedAt: meta.generatedAt,
    period: meta.period,
    sites: [
      {
        host: 'khe.ee',
        ...totals(account.kheTotal),
        topPages: topPages(account.kheTopPages)
      },
      {
        host: 'games.khe.ee',
        ...totals(account.gamesTotal),
        topPages: topPages(account.gamesTopPages)
      }
    ],
    uptimeSummary: {
      source: 'manual',
      publicServicesHealthy: null
    },
    visibility: 'internal',
    notes: [
      'Internal operational report. Do not publish this raw file.',
      'Public portfolio metrics are written separately from an allowlist.'
    ]
  }
}];

const source = $input.first().json;
if (source.errors?.length) {
  throw new Error(`Cloudflare GraphQL error: ${JSON.stringify(source.errors)}`);
}

const account = source.data?.viewer?.accounts?.[0] ?? {};
const meta = $('Build Cloudflare Query').first().json;

function totals(rows) {
  const row = Array.isArray(rows) ? rows[0] : undefined;
  return {
    pageViews: Number(row?.count ?? 0),
    visits: Number(row?.sum?.visits ?? 0)
  };
}

return [{
  json: {
    generatedAt: meta.generatedAt,
    periodDays: meta.period.days,
    sites: [
      {
        host: 'khe.ee',
        ...totals(account.kheTotal)
      },
      {
        host: 'games.khe.ee',
        ...totals(account.gamesTotal)
      }
    ],
    source: 'Cloudflare Web Analytics + n8n'
  }
}];
